## 1. Dijkstra’s Shortest Path for Vehicle Routes

This example:
- Defines a simple graph representing roads between intersections.
- Implements Dijkstra’s algorithm to find the shortest path from a start to an end node.
- Returns the path as a list of nodes.

```java
import java.util.*;

public class VehicleRouteOptimizer {

    // Edge class to represent a road segment
    private static class Edge {
        int to;
        double weight; // e.g., travel time or distance

        Edge(int to, double weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    // Graph represented as adjacency list
    private static class Graph {
        private final Map<Integer, List<Edge>> adj;

        Graph() {
            adj = new HashMap<>();
        }

        void addEdge(int from, int to, double weight) {
            adj.computeIfAbsent(from, k -> new ArrayList<>()).add(new Edge(to, weight));
            // If roads are undirected, also add reverse edge:
            adj.computeIfAbsent(to, k -> new ArrayList<>()).add(new Edge(from, weight));
        }

        List<Edge> getNeighbors(int node) {
            return adj.getOrDefault(node, Collections.emptyList());
        }
    }

    /**
     * Dijkstra's algorithm to find the shortest path from start to end.
     *
     * @param graph   the graph
     * @param start   starting node
     * @param end     destination node
     * @return list of nodes in the shortest path, or empty if no path exists
     */
    public static List<Integer> dijkstra(Graph graph, int start, int end) {
        if (start == end) {
            return Arrays.asList(start);
        }

        Map<Integer, Double> dist = new HashMap<>();
        Map<Integer, Integer> prev = new HashMap<>();
        Set<Integer> visited = new HashSet<>();

        for (int node : graph.adj.keySet()) {
            dist.put(node, Double.MAX_VALUE);
            prev.put(node, null);
        }
        dist.put(start, 0.0);

        PriorityQueue<NodeWithDist> pq = new PriorityQueue<>(Comparator.comparingDouble(n -> n.dist));
        pq.add(new NodeWithDist(start, 0.0));

        while (!pq.isEmpty()) {
            NodeWithDist current = pq.poll();
            int u = current.node;

            if (visited.contains(u)) {
                continue;
            }
            visited.add(u);

            if (u == end) {
                break;
            }

            for (Edge e : graph.getNeighbors(u)) {
                int v = e.to;
                double newDist = dist.get(u) + e.weight;

                if (newDist < dist.get(v)) {
                    dist.put(v, newDist);
                    prev.put(v, u);
                    pq.add(new NodeWithDist(v, newDist));
                }
            }
        }

        // Reconstruct path
        List<Integer> path = new ArrayList<>();
        if (!prev.containsKey(end)) {
            return Collections.emptyList();
        }

        int curr = end;
        while (curr != null) {
            path.add(curr);
            curr = prev.get(curr);
        }
        Collections.reverse(path);
        return path;
    }

    // Helper class for priority queue
    private static class NodeWithDist implements Comparable<NodeWithDist> {
        final int node;
        final double dist;

        NodeWithDist(int node, double dist) {
            this.node = node;
            this.dist = dist;
        }

        @Override
        public int compareTo(NodeWithDist other) {
            return Double.compare(this.dist, other.dist);
        }
    }

    public static void main(String[] args) {
        Graph graph = new Graph();

        // Example road network (undirected)
        // Nodes: 0, 1, 2, 3, 4
        graph.addEdge(0, 1, 5.0);
        graph.addEdge(0, 2, 3.0);
        graph.addEdge(1, 2, 2.0);
        graph.addEdge(1, 3, 4.0);
        graph.addEdge(2, 3, 1.0);
        graph.addEdge(2,

