    private static readonly List<string> Line1Options = new List<string>
    {
        "A lone tree stands",
        "Silent in the rain",
        "Roots deep in earth",
        "Branches reach up",
        "Old oak in shade"
    };

    private static readonly List<string> Line2Options = new List<string>
    {
        "Mist wraps around",
        "Soft fog fills the air",
        "Dew drops on leaves",
        "Clouds drift slowly",
        "Silence falls down"
    };

    private static readonly List<string> Line3Options = new List<string>
    {
        "Peaceful now",
        "Quietly sleeps",
        "Dreams of spring",
        "Still and calm",
        "Waiting for dawn"
    };

    public static string GenerateHaiku()
    {
        // Randomly select one phrase from each line
        var line1 = Line1Options[new Random().Next(Line1Options.Count)];
        var line2 = Line2Options[new Random().Next(Line2Options.Count)];
        var line3 = Line3Options[new Random().Next(Line3Options.Count)];

        // Combine lines
        return $"{line1}\n{line2}\n{line3}";
    }

    // Helper to count syllables (Simplified for demonstration)
    private static int CountSyllables(string word)
    {
        if (string.IsNullOrEmpty(word)) return 0;
        // Basic heuristic: vowels count as syllables, minus silent 'e' at end
        int count = 0;
        foreach (char c in word.ToLower())
        {
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u')
            {
                count++;
            }
        }
        return count;
    }

